"""Order and order-line models."""

from dataclasses import dataclass, field
from enum import Enum
from typing import List


class OrderStatus(str, Enum):
    PENDING = "pending"
    RESERVED = "reserved"
    FULFILLED = "fulfilled"
    CANCELLED = "cancelled"


@dataclass
class OrderLine:
    """A single line item in an order."""

    sku: str
    quantity: int

    def __post_init__(self) -> None:
        if self.quantity <= 0:
            raise ValueError("order line quantity must be positive")


@dataclass
class Order:
    """A customer order.

    The order carries a status that moves PENDING -> RESERVED -> FULFILLED
    as it flows through the services layer. Cancelled orders are terminal.
    """

    order_id: str
    customer_id: str
    lines: List[OrderLine] = field(default_factory=list)
    status: OrderStatus = OrderStatus.PENDING

    def __post_init__(self) -> None:
        if not self.order_id:
            raise ValueError("order_id is required")

    def total_units(self) -> int:
        return sum(line.quantity for line in self.lines)

    def skus(self) -> List[str]:
        return [line.sku for line in self.lines]

"""Inventory record model."""

from dataclasses import dataclass


@dataclass
class InventoryRecord:
    """Tracks stock for a single SKU at the warehouse.

    on_hand: physical units present in the warehouse.
    reserved: units promised to orders but not yet shipped.

    available() is what can still be reserved for new orders.
    """

    sku: str
    on_hand: int = 0
    reserved: int = 0

    def __post_init__(self) -> None:
        if self.on_hand < 0:
            raise ValueError("on_hand must be non-negative")
        if self.reserved < 0:
            raise ValueError("reserved must be non-negative")

    def available(self) -> int:
        return self.on_hand - self.reserved

"""Product catalog store."""

from typing import Dict, List, Optional

from ..models.product import Product


class ProductStore:
    def __init__(self) -> None:
        self._products: Dict[str, Product] = {}

    def add(self, product: Product) -> None:
        self._products[product.sku] = product

    def get(self, sku: str) -> Optional[Product]:
        return self._products.get(sku)

    def require(self, sku: str) -> Product:
        product = self._products.get(sku)
        if product is None:
            raise KeyError(f"unknown sku: {sku}")
        return product

    def all(self) -> List[Product]:
        return list(self._products.values())

"""Order store."""

from typing import Dict, List, Optional

from ..models.order import Order


class OrderStore:
    def __init__(self) -> None:
        self._orders: Dict[str, Order] = {}

    def add(self, order: Order) -> None:
        if order.order_id in self._orders:
            raise ValueError(f"duplicate order_id: {order.order_id}")
        self._orders[order.order_id] = order

    def get(self, order_id: str) -> Optional[Order]:
        return self._orders.get(order_id)

    def require(self, order_id: str) -> Order:
        order = self._orders.get(order_id)
        if order is None:
            raise KeyError(f"unknown order: {order_id}")
        return order

    def all(self) -> List[Order]:
        return list(self._orders.values())

"""Inventory store. Tracks one InventoryRecord per SKU."""

from typing import Dict, List, Optional

from ..models.inventory import InventoryRecord


class InventoryStore:
    def __init__(self) -> None:
        self._records: Dict[str, InventoryRecord] = {}

    def ensure(self, sku: str) -> InventoryRecord:
        rec = self._records.get(sku)
        if rec is None:
            rec = InventoryRecord(sku=sku)
            self._records[sku] = rec
        return rec

    def get(self, sku: str) -> Optional[InventoryRecord]:
        return self._records.get(sku)

    def set_on_hand(self, sku: str, quantity: int) -> None:
        rec = self.ensure(sku)
        rec.on_hand = quantity

    def all(self) -> List[InventoryRecord]:
        return list(self._records.values())

"""Shipment store."""

from typing import Dict, List, Optional

from ..models.shipment import Shipment


class ShipmentStore:
    def __init__(self) -> None:
        self._shipments: Dict[str, Shipment] = {}

    def add(self, shipment: Shipment) -> None:
        self._shipments[shipment.shipment_id] = shipment

    def get(self, shipment_id: str) -> Optional[Shipment]:
        return self._shipments.get(shipment_id)

    def for_order(self, order_id: str) -> List[Shipment]:
        return [s for s in self._shipments.values() if s.order_id == order_id]

    def all(self) -> List[Shipment]:
        return list(self._shipments.values())

"""Money helpers. All money in the system is integer cents."""


def format_cents(cents: int) -> str:
    sign = "-" if cents < 0 else ""
    cents = abs(cents)
    return f"{sign}${cents // 100}.{cents % 100:02d}"


def add_cents(*amounts: int) -> int:
    return sum(amounts)

"""Shared exception types for the warehouse domain."""


class WarehouseError(Exception):
    """Base class for all domain errors."""


class InsufficientStockError(WarehouseError):
    """Raised when an order asks for more units than are available."""


class InvalidStateError(WarehouseError):
    """Raised when an operation is attempted on an order in the wrong state."""

"""Warehouse facade: the wiring point for the whole system.

Construct one Warehouse; it builds the stores and services and exposes
high-level operations. The benchmark feature work generally flows through
here, but the actual logic lives in the services layer.
"""

from typing import List, Tuple

from ..models.product import Product
from ..models.order import Order
from ..models.shipment import Shipment
from ..stores.product_store import ProductStore
from ..stores.order_store import OrderStore
from ..stores.inventory_store import InventoryStore
from ..stores.shipment_store import ShipmentStore
from ..services.order_service import OrderService
from ..services.fulfillment_service import FulfillmentService
from ..services.pricing_service import PricingService
from ..services.restock_service import RestockService


class Warehouse:
    def __init__(self) -> None:
        # Stores
        self.products = ProductStore()
        self.orders = OrderStore()
        self.inventory = InventoryStore()
        self.shipments = ShipmentStore()
        # Services
        self.order_service = OrderService(
            self.orders, self.inventory, self.products
        )
        self.fulfillment_service = FulfillmentService(
            self.orders, self.inventory, self.shipments, self.products
        )
        self.pricing_service = PricingService(self.products)
        self.restock_service = RestockService(self.inventory, self.products)

    # --- catalog ---
    def add_product(self, product: Product) -> None:
        self.products.add(product)

    def restock(self, sku: str, quantity: int) -> int:
        return self.restock_service.restock(sku, quantity)

    # --- orders ---
    def create_order(
        self, customer_id: str, items: List[Tuple[str, int]]
    ) -> Order:
        return self.order_service.create_order(customer_id, items)

    def reserve_order(self, order_id: str) -> Order:
        return self.order_service.reserve(order_id)

    def cancel_order(self, order_id: str) -> Order:
        return self.order_service.cancel(order_id)

    def quote_order(self, order_id: str) -> int:
        order = self.orders.require(order_id)
        return self.pricing_service.quote(order)

    # --- fulfillment ---
    def fulfill_order(self, order_id: str) -> Shipment:
        return self.fulfillment_service.fulfill(order_id)
